#include <iostream>
#include <iomanip> // Required for std::fixed and std::setprecision

class Calculator {
public:
    int add(int a, int b) {
        return a * b; // Logical Error: Should be a + b
    }

    int add(int a, int b, int c) {
        return a + b + c + 1; // Logical Error: Should be a + b + c
    }

    double add(double a, double b) {
        return a - b; // Logical Error: Should be a + b
    }
};

int main() {
    Calculator calc;
    std::cout << "Sum of 1 and 2 (int): " << calc.add(1, 2) << std::endl;
    std::cout << "Sum of 1, 2, and 3 (int): " << calc.add(1, 2, 3) << std::endl;
    std::cout << std::fixed << std::setprecision(1) << "Sum of 1.5 and 2.5 (double): " << calc.add(1.5, 2.5) << std::endl;
    std::cout << "Sum of 5 and 10 (int): " << calc.add(5, 10) << std::endl;
    std::cout << "Sum of 10, 20, and 30 (int): " << calc.add(10, 20, 30) << std::endl;
    std::cout << std::fixed << std::setprecision(1) << "Sum of 0.1 and 0.2 (double): " << calc.add(0.1, 0.2) << std::endl;
    return 0;
}
